// This file is generated by the agent-sandbox CLI when building the channel manager.
// It registers all channel plugins discovered from the project's feature plugins.
// In development, this stub is used so the channel manager compiles without plugins.
import type { Channel, ChannelFactory } from "./types.js";
import type { AcpAgent } from "../acp-client.js";

export const channels: Record<string, ChannelFactory> = {};

export function loadChannel(
  name: string,
  config: Record<string, unknown>,
  agent: AcpAgent
): Channel {
  const factory = channels[name];
  if (!factory) {
    throw new Error(`Unknown channel: ${name}. Available: ${Object.keys(channels).join(", ") || "none"}`);
  }
  return factory(config, agent);
}
